fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let k_val = k as usize;
    let m = k_val / 2;

    // Compute original profit
    let original_profit: i64 = prices.iter().zip(strategy.iter()).map(|(&p, &s)| s * p).sum();

    // Compute A and B arrays
    let mut A = vec![0; n];
    let mut B = vec![0; n];
    for i in 0..n {
        A[i] = -strategy[i] * prices[i];
        B[i] = (1 - strategy[i]) * prices[i];
    }

    // Compute prefix sums for A and B
    let mut prefixA = vec![0; n + 1];
    let mut prefixB = vec![0; n + 1];
    for i in 0..n {
        prefixA[i + 1] = prefixA[i] + A[i];
        prefixB[i + 1] = prefixB[i] + B[i];
    }

    let mut max_delta = i64::MIN;
    let max_i = n - k_val;
    for i in 0..=max_i {
        let start1 = i;
        let end1 = i + m - 1;
        let start2 = i + m;
        let end2 = i + k_val - 1;

        let sumA = prefixA[end1 + 1] - prefixA[start1];
        let sumB = prefixB[end2 + 1] - prefixB[start2];
        let delta = sumA + sumB;

        if delta > max_delta {
            max_delta = delta;
        }
    }

    let result = if max_delta > 0 { original_profit + max_delta } else { original_profit };
    result
}
